    question: "Use extern alias for assembly-level namespace resolution.",
    mathSolution: "Resolving conflicts between assemblies with same namespace.",
    codeSolution: "// Note: This requires two assemblies with same namespace\n// File: Assembly1.cs\n// namespace Common { public class Helper { } }\n\n// File: Assembly2.cs  \n// namespace Common { public class Helper { } }\n\n// File: Program.cs with extern aliases\n// First, add references with aliases in .csproj:\n// <Reference Include=\"Assembly1\" Aliases=\"AssemblyA\" />\n// <Reference Include=\"Assembly2\" Aliases=\"AssemblyB\" />\n\n// Then use extern alias\nextern alias AssemblyA;\nextern alias AssemblyB;\n\nusing System;\n\nclass Program\n{\n    static void Main()\n    {\n        // Using classes from different assemblies with same namespace\n        var helperA = new AssemblyA::Common.Helper();\n        var helperB = new AssemblyB::Common.Helper();\n        \n        Console.WriteLine(\"Using extern alias to resolve assembly conflicts\");\n        Console.WriteLine(\"AssemblyA: {0}\", helperA.GetType());\n        Console.WriteLine(\"AssemblyB: {0}\", helperB.GetType());\n    }\n}\n\n// Example without extern alias (simpler conflict resolution)\n// In .csproj:\n// <Using Include=\"MyNamespace\" Alias=\"MyAlias\" />",
    hint: "Extern aliases resolve naming conflicts between assemblies.",
